// Lấy 15 hàng mới nhất
const latestItems = sortedItems.slice(0, 15);

// Sắp xếp lại theo thời gian tăng dần để giữ đúng thứ tự hội thoại
const finalSorted = [...latestItems].sort((a, b) => new Date(a.json.createdAt) - new Date(b.json.createdAt));

// Trả về kết quả
return finalSorted;

const inputItems = items;

if (inputItems.length === 0) {
  return [];
}

// Sort messages by creation time (ascending)
const sortedItems = [...inputItems].sort(
  (a, b) => new Date(a.json.createdAt) - new Date(b.json.createdAt)
);

// Format helper for YYYY-MM-DD HH:mm:ss in Vietnam timezone
function formatVNDateTime(date) {
  return date.toLocaleString('en-CA', { timeZone: 'Asia/Ho_Chi_Minh' });
}

// Helper to get date string only (YYYY-MM-DD)
function getVNDate(date) {
  return new Date(date).toLocaleDateString('en-CA', { timeZone: 'Asia/Ho_Chi_Minh' });
}

let sessions = [];
let currentSession = [];
let lastDate = null;

sortedItems.forEach(item => {
  const createdAt = new Date(item.json.createdAt);
  const currentDate = getVNDate(createdAt);

  if (lastDate && currentDate !== lastDate) {
    // Push previous session
    sessions.push(currentSession);
    currentSession = [];
  }

  currentSession.push(item);
  lastDate = currentDate;
});

// Push the final session
if (currentSession.length > 0) {
  sessions.push(currentSession);
}

// Get today's date in Vietnam timezone
const todayVN = getVNDate(new Date());

// Split sessions into old and current
let oldSessionHistory = '';
let nowSessionHistory = '';

sessions.forEach(session => {
  const sessionDate = getVNDate(session[0].json.createdAt);
  let sessionBlock = `--- 🕒 Session started at ${formatVNDateTime(new Date(session[0].json.createdAt))} ---\n`;

  session.forEach(item => {
    const userText = item.json.user_text;
    const pageText = item.json.page_text;   // <-- lấy phản hồi từ Page
    const botRep = item.json.bot_rep;       // <-- phản hồi từ AI nếu có
    const createdAtFormatted = formatVNDateTime(new Date(item.json.createdAt));
    const updatedAtFormatted = formatVNDateTime(new Date(item.json.updatedAt));

    if (userText) {
      sessionBlock += `Human [${createdAtFormatted}]: ${userText}\n`;
    }
    if (pageText) {
      sessionBlock += `Page [${updatedAtFormatted}]: ${pageText}\n`;
    }
    if (botRep) {
      sessionBlock += `AI [${updatedAtFormatted}]: ${botRep}\n`;
    }
  });

  sessionBlock = sessionBlock.trim() + '\n';

  if (sessionDate === todayVN) {
    nowSessionHistory += sessionBlock;
  } else {
    oldSessionHistory += sessionBlock;
  }
});

// Calculate min_id (smallest id in the list)
const minId = Math.min(...sortedItems.map(item => item.json.id));

// Final output
return [
  {
    json: {
      old_session_history: oldSessionHistory.trim(),
      now_session_history: nowSessionHistory.trim(),
      min_id: minId
    }
  }
];

// Lấy danh sách input
const inputItems = items;

// Nếu danh sách rỗng, trả về rỗng
if (inputItems.length === 0) {
  return [];
}

// Sắp xếp theo id tăng dần
const sortedItems = [...inputItems].sort((a, b) => a.json.id - b.json.id);

// Tạo merged_message từ các user_text không null
const mergedMessage = sortedItems
  .map(item => item.json.user_text)
  .filter(text => text !== null && text !== undefined)
  .join(' ');

// Tìm item có id lớn nhất
let maxItem = sortedItems[sortedItems.length - 1];

// Thêm các trường vào item lớn nhất
maxItem.json.merged_message = mergedMessage;
// Trả về item có id lớn nhất kèm merged_message và history
return [maxItem];

const MAX_LEN = 2000;

/* === Get input === */
let text = ($input.first().json.output || "").trim();
if (!text) return [];

/* --- Fix escape JSON: đổi \\n, \\\n thành \n thật --- */
text = text.replace(/\\+/g, '\\');   // gộp nhiều \ thành 1
text = text.replace(/\\n/g, '\n');   // đổi thành newline thật

/* ---------- 1) Markdown → Facebook Markdown ---------- */
function mdToFacebook(md){
  let s = md;

  // code block → giữ nguyên
  s = s.replace(/```([\s\S]*?)```/g, (m,p1)=>`\`\`\n${p1.trim()}\n\`\`\``);

  // inline code
  s = s.replace(/`([^`]+)`/g, (m,p1)=>`\`${p1}\``);

  // bold (**text**) → *text*
  s = s.replace(/\*\*([^*]+)\*\*/g, '*$1*');

  // italic (_text_) → giữ nguyên

  // underline & strike → bỏ
  s = s.replace(/__([^_]+)__/g, '$1');
  s = s.replace(/~~([^~]+)~~/g, '$1');

  // headers → bold
  s = s.replace(/^(#{1,6})\s+(.+)$/gm, (m, hashes, content)=>`*${content.trim()}*`);

  // list markers → bullet list Messenger
  s = s.replace(/^[\-\*\+]\s+(.+)$/gm, '* $1');

  // links → giữ text
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (m,txt,url)=>txt);

  return s.trim();
}

/* ---------- 2) HTML → Facebook Markdown ---------- */
function htmlToFbMarkdown(input){
  let s = input;

  s = s.replace(/<br\s*\/?>/gi, '\n');

  // headers → bold
  s = s.replace(/<h[1-6][^>]*>([\s\S]*?)<\/h[1-6]>/gi, (m, inner)=>`*${inner.trim()}*`);

  // bold / italic
  s = s.replace(/<\/?strong[^>]*>/gi, '*');
  s = s.replace(/<\/?b[^>]*>/gi, '*');
  s = s.replace(/<\/?em[^>]*>/gi, '_');
  s = s.replace(/<\/?i[^>]*>/gi, '_');

  // paragraphs/divs → newline
  s = s.replace(/<\/?(p|div)[^>]*>/gi, '\n');

  // lists → bullet
  s = s.replace(/<li[^>]*>/gi, '* ').replace(/<\/li>/gi, '\n');
  s = s.replace(/<\/?(ul|ol)[^>]*>/gi, '');

  // remove all other tags
  s = s.replace(/<\/?[^>]+>/g, '');

  return s.trim();
}

/* ---------- 3) Normalize content ---------- */
function normalizeToFacebookMarkdown(input){
  const looksLikeMd = /(^|\s)[*_`~]|^#{1,6}\s|```/.test(input);
  let s = looksLikeMd ? mdToFacebook(input) : htmlToFbMarkdown(input);

  // collapse nhiều newline thành 1
  s = s.replace(/\n{3,}/g, '\n\n');

  // xoá ký tự "\" thừa còn sót
  s = s.replace(/\\+/g, '');

  return s.trim();
}

/* ---------- 4) Split by newlines (smart split) ---------- */
function splitMarkdownSmart(text, maxLen) {
  const lines = text.split('\n');
  const chunks = [];
  let buffer = '';

  for (const line of lines) {
    if ((buffer + line + '\n').length > maxLen) {
      if (buffer.trim()) chunks.push(buffer.trim());
      buffer = line + '\n';
    } else {
      buffer += line + '\n';
    }
  }

  if (buffer.trim()) chunks.push(buffer.trim());

  return chunks.map(c => c.replace(/\n+$/,''));
}

/* ===== Run ===== */
const normalized = normalizeToFacebookMarkdown(text);
const chunks = splitMarkdownSmart(normalized, MAX_LEN);

return chunks.map(c => ({ json: { text: c } }));
